class PaymentService extends ChangeNotifier {
  final PaymentConfiguration config;
  final PaymentGateway gateway;
  final PaymentRepository repository;
  PaymentStatus _status = PaymentStatus.idle;
  String? _lastError;
  PaymentResult? _lastResult;

  PaymentService({
    required this.config,
    required this.gateway,
    PaymentRepository? repository,
  }) : repository = repository ?? PaymentRepository();

  PaymentStatus get status => _status;
  String? get lastError => _lastError;
  PaymentResult? get lastResult => _lastResult;

  Future<void> initialize() async {
    _setStatus(PaymentStatus.initializing);
    try {
      await gateway.initialize(
        environment: config.environment,
        merchantId: config.merchantId,
        publicKey: config.publicKey,
      );
      _setStatus(PaymentStatus.ready);
    } catch (e) {
      _lastError = e.toString();
      _setStatus(PaymentStatus.failed);
      rethrow;
    }
  }

  Future<PaymentResult> pay(PaymentRequest request) async {
    _setStatus(PaymentStatus.processing);
    _lastError = null;
    try {
      final result = await gateway.process(request);
      _lastResult = result;
      _setStatus(result.status);
      if (result.isSuccess) {
        repository.add(
          TransactionRecord(
            id: result.transactionId ?? request.id,
            requestId: request.id,
            status: describeEnum(result.status),
            paymentMethod: describeEnum(request.methodType),
            currency: request.currency.toUpperCase(),
            amountMinor: (request.amount * 100).round(),
            createdAt: DateTime.now().toUtc(),
            details: result.rawResponse,
          ),
        );
      }
      return result;
    } catch (e) {
      _lastError = e.toString();
      _setStatus(PaymentStatus.failed);
      return PaymentResult(
        requestId: request.id,
        status: PaymentStatus.failed,
        errorCode: 'payment_exception',
        errorMessage: e.toString(),
      );
    }
  }

  Future<PaymentResult> restore(String transactionId) async {
    _setStatus(PaymentStatus.processing);
    try {
      final result = await gateway.restoreTransaction(transactionId);
      _lastResult = result;
      _setStatus(result.status);
      return result;
    } catch (e) {
      _lastError = e.toString();
      _setStatus(PaymentStatus.failed);
      return PaymentResult(
        requestId: transactionId,
        status: PaymentStatus.failed,
        errorCode: 'restore_exception',
        errorMessage: e.toString(),
      );
    }
  }

  Future<bool> supports(PaymentMethodType type) => gateway.isAvailable(type);

  void _setStatus(PaymentStatus next) {
    _status = next;
    notifyListeners();
  }
}

class PaymentLauncher extends StatefulWidget {
  final PaymentService service;
  final PaymentRequest request;
