  final ValueChanged<PaymentResult>? onCompleted;
  final ValueChanged<String>? onError;

  const PaymentLauncher({
    super.key,
    required this.service,
    required this.request,
    this.loadingBuilder,
    this.onCompleted,
    this.onError,
  });

  @override
  State<PaymentLauncher> createState() => _PaymentLauncherState();
}

class _PaymentLauncherState extends State<PaymentLauncher> {
  bool _started = false;

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
    if (!_started) {
      _started = true;
      unawaited(_run());
    }
  }

  Future<void> _run() async {
    try {
      final result = await widget.service.pay(widget.request);
      if (!mounted) return;
      widget.onCompleted?.call(result);
      if (result.errorMessage != null && !result.isSuccess) {
        widget.onError?.call(result.errorMessage!);
      }
    } catch (e) {
      if (!mounted) return;
      widget.onError?.call(e.toString());
    }
  }

  @override
  Widget build(BuildContext context) {
    return widget.loadingBuilder?.call(context) ??
        const Center(child: SizedBox(width: 24, height: 24, child: Placeholder()));
  }
}

class PaymentModule {
  final PaymentService service;

  PaymentModule._(this.service);

  static Future<PaymentModule> configure(PaymentConfiguration config) async {
    final gateway = HttpPaymentGateway(config: config);
    final service = PaymentService(config: config, gateway: gateway);
    await service.initialize();
    return PaymentModule._(service);
  }
}

