Future<void> initializePaymentModule({
  required PaymentEnvironment environment,
  required String merchantId,
  required String publicKey,
  required String gatewayEndpoint,
  String? appleMerchantIdentifier,
  String? googlePayMerchantName,
}) async {
  final config = PaymentConfiguration(
    environment: environment,
    merchantId: merchantId,
    publicKey: publicKey,
    gatewayEndpoint: gatewayEndpoint,
    appleMerchantIdentifier: appleMerchantIdentifier,
    googlePayMerchantName: googlePayMerchantName,
  );
  final module = await PaymentModule.configure(config);
  unawaited(module.service.supports(PaymentMethodType.applePay));
  unawaited(module.service.supports(PaymentMethodType.googlePay));
}